import { NextResponse } from "next/server";

import {
  recordClinicalAudit,
  requireClinicalContext,
} from "@/lib/clinical/context";
import { queueClinicalWorkflowNotification } from "@/lib/clinical/notification-service";
import { recordWorkflowEvent } from "@/lib/clinical/workflow";
import { prisma } from "@/lib/prisma";

type Row = Record<string, unknown>;

const toNumber = (
  value: unknown
) => {
  const parsed = Number(value);
  return Number.isFinite(parsed) &&
    parsed > 0
    ? parsed
    : null;
};

const text = (value: unknown) =>
  String(value || "").trim();

export async function GET(
  request: Request
) {
  const auth =
    await requireClinicalContext(
      request
    );

  if (auth.response) {
    return auth.response;
  }

  const context = auth.context!;
  const { searchParams } =
    new URL(request.url);
  const appointmentId = toNumber(
    searchParams.get("id")
  );
  const viewDate =
    searchParams.get("date") ||
    new Date()
      .toISOString()
      .slice(0, 10);
  const appointmentFilter = appointmentId
    ? "AND a.id = $4"
    : "AND a.appointment_date = $4::date";

  const [appointments, patients, doctors] =
    await Promise.all([
      prisma.$queryRawUnsafe<Row[]>(
        `
        SELECT
          a.*,
          COALESCE(p.first_name, '') || ' ' || COALESCE(p.last_name, '') AS patient_name,
          p.patient_uid,
          d.full_name AS doctor_name,
          dep.department_name
        FROM appointments a
        LEFT JOIN patients p ON p.id = a.patient_id
        LEFT JOIN doctors d ON d.id = a.doctor_id
        LEFT JOIN departments dep ON dep.id = a.department_id
        WHERE a.tenant_id = $1
          AND a.hospital_id = $2
          AND a.branch_id = $3
          ${appointmentFilter}
          AND COALESCE(a.is_deleted, false) = false
        ORDER BY a.start_time ASC NULLS LAST, a.id DESC
        `,
        context.tenantId,
        context.hospitalId,
        context.branchId,
        appointmentId || viewDate
      ),
      prisma.$queryRawUnsafe<Row[]>(
        `
        SELECT id, patient_uid, first_name, last_name, phone
        FROM patients
        WHERE tenant_id = $1
          AND hospital_id = $2
          AND branch_id = $3
          AND COALESCE(is_deleted, false) = false
        ORDER BY created_at DESC
        LIMIT 200
        `,
        context.tenantId,
        context.hospitalId,
        context.branchId
      ),
      prisma.$queryRawUnsafe<Row[]>(
        `
        SELECT id, full_name, specialization, status
        FROM doctors
        WHERE tenant_id = $1
          AND hospital_id = $2
          AND branch_id = $3
          AND COALESCE(is_deleted, false) = false
        ORDER BY full_name ASC
        LIMIT 100
        `,
        context.tenantId,
        context.hospitalId,
        context.branchId
      ),
    ]);

  return NextResponse.json({
    date: viewDate,
    appointments,
    patients,
    doctors,
  });
}

export async function POST(
  request: Request
) {
  const auth =
    await requireClinicalContext(
      request
    );

  if (auth.response) {
    return auth.response;
  }

  const context = auth.context!;
  const body =
    await request.json();
  const patientId = toNumber(
    body.patient_id
  );

  if (!patientId) {
    return NextResponse.json(
      {
        error:
          "Select a patient before booking an appointment.",
      },
      {
        status: 400,
      }
    );
  }

  if (!text(body.appointment_date)) {
    return NextResponse.json(
      {
        error:
          "Appointment date is required.",
      },
      {
        status: 400,
      }
    );
  }

  const tokenRows =
    await prisma.$queryRawUnsafe<
      { next_token: number }[]
    >(
      `
      SELECT COALESCE(MAX(NULLIF(regexp_replace(token_number, '\\D', '', 'g'), '')::int), 0) + 1 AS next_token
      FROM appointments
      WHERE tenant_id = $1
        AND hospital_id = $2
        AND branch_id = $3
        AND appointment_date = $4::date
      `,
      context.tenantId,
      context.hospitalId,
      context.branchId,
      body.appointment_date
    );
  const token = `T-${String(
    tokenRows[0]?.next_token || 1
  ).padStart(3, "0")}`;
  const uid = `APT-${Date.now()}`;

  const rows =
    await prisma.$queryRawUnsafe<Row[]>(
      `
      INSERT INTO appointments (
        tenant_id,
        clinic_id,
        hospital_id,
        branch_id,
        patient_id,
        doctor_id,
        department_id,
        appointment_uid,
        appointment_date,
        start_time,
        end_time,
        appointment_type,
        status,
        token_number,
        queue_status,
        reason,
        notes,
        metadata,
        created_by,
        updated_by,
        created_at,
        updated_at,
        is_deleted
      )
      VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9::date,$10::time,$11::time,$12,'BOOKED',$13,'WAITING',$14,$15,$16::jsonb,$17,$17,CURRENT_TIMESTAMP,CURRENT_TIMESTAMP,false)
      RETURNING *
      `,
      context.tenantId,
      context.clinicId,
      context.hospitalId,
      context.branchId,
      patientId,
      toNumber(body.doctor_id),
      toNumber(body.department_id),
      uid,
      body.appointment_date,
      text(body.start_time) || null,
      text(body.end_time) || null,
      text(body.appointment_type) ||
        "OPD",
      token,
      text(body.reason) || null,
      text(body.notes) || null,
      JSON.stringify(
        body.metadata || {}
      ),
      context.user.id ?? null
    );
  const appointment = rows[0];

  await recordClinicalAudit(context, {
    moduleName: "appointments",
    action: "create",
    entityType: "appointment",
    entityId:
      Number(appointment.id),
    summary:
      "Clinical appointment booked",
    payload: {
      appointment_uid: uid,
      token_number: token,
      patient_id: patientId,
    },
  });

  await recordWorkflowEvent(context, {
    patientId,
    appointmentId: Number(appointment.id),
    workflowStage: "APPOINTMENT",
    status: "BOOKED",
    summary: `Appointment booked with token ${token}.`,
    sourceTable: "appointments",
    sourceId: Number(appointment.id),
    metadata: {
      appointment_uid: uid,
      token_number: token,
      doctor_id: appointment.doctor_id,
      department_id: appointment.department_id,
    },
  });

  await queueClinicalWorkflowNotification(context, {
    templateKey: "appointment_booked",
    patientId,
    appointmentId: Number(appointment.id),
    sourceModule: "appointments",
    sourceRecordId: Number(appointment.id),
    variables: {
      doctor_name: appointment.doctor_id ? `Doctor #${appointment.doctor_id}` : "Doctor",
      department: appointment.department_id ? `Department #${appointment.department_id}` : "Department",
      appointment_date: String(appointment.appointment_date || body.appointment_date || "-"),
      appointment_time: String(appointment.start_time || "-"),
      appointment_number: appointment.appointment_uid || appointment.id,
    },
  });

  return NextResponse.json(
    appointment,
    {
      status: 201,
    }
  );
}

export async function PATCH(
  request: Request
) {
  const auth =
    await requireClinicalContext(
      request
    );

  if (auth.response) {
    return auth.response;
  }

  const context = auth.context!;
  const body =
    await request.json();
  const id = toNumber(body.id);

  if (!id) {
    return NextResponse.json(
      {
        error:
          "Appointment id is required.",
      },
      {
        status: 400,
      }
    );
  }

  let status = text(body.status) || null;
  let queueStatus = text(body.queue_status) || null;

  if (
    status === "CHECKED_IN" ||
    queueStatus === "CHECKED_IN"
  ) {
    status = "CHECKED_IN";
    queueStatus = "WAITING_FOR_VITALS";
  }

  const rows =
    await prisma.$queryRawUnsafe<Row[]>(
      `
      UPDATE appointments
      SET doctor_id = COALESCE($5, doctor_id),
          department_id = COALESCE($6, department_id),
          appointment_date = COALESCE($7::date, appointment_date),
          start_time = COALESCE($8::time, start_time),
          end_time = COALESCE($9::time, end_time),
          appointment_type = COALESCE($10, appointment_type),
          reason = COALESCE($11, reason),
          notes = COALESCE($12, notes),
          status = COALESCE($13, status),
          queue_status = COALESCE($14, queue_status),
          cancellation_reason = CASE WHEN $13 = 'CANCELLED' THEN COALESCE($15, cancellation_reason) ELSE cancellation_reason END,
          updated_by = $16,
          updated_at = CURRENT_TIMESTAMP
      WHERE id = $1
        AND tenant_id = $2
        AND hospital_id = $3
        AND branch_id = $4
        AND COALESCE(is_deleted, false) = false
      RETURNING *
      `,
      id,
      context.tenantId,
      context.hospitalId,
      context.branchId,
      toNumber(body.doctor_id),
      toNumber(body.department_id),
      text(body.appointment_date) || null,
      text(body.start_time) || null,
      text(body.end_time) || null,
      text(body.appointment_type) || null,
      text(body.reason) || null,
      text(body.notes) || null,
      status,
      queueStatus,
      text(body.cancellation_reason) || null,
      context.user.id ?? null
    );

  if (!rows.length) {
    return NextResponse.json(
      {
        error:
          "Appointment not found.",
      },
      {
        status: 404,
      }
    );
  }

  await recordClinicalAudit(context, {
    moduleName: "appointments",
    action: "update",
    entityType: "appointment",
    entityId: id,
    summary:
      "Clinical appointment status updated",
    payload: {
      status,
      queue_status:
        queueStatus,
    },
  });

  if (status || queueStatus) {
    await recordWorkflowEvent(context, {
      patientId: Number(rows[0].patient_id),
      appointmentId: id,
      workflowStage: "APPOINTMENT",
      status: queueStatus || status || "UPDATED",
      summary: `Appointment moved to ${queueStatus || status}.`,
      sourceTable: "appointments",
      sourceId: id,
      metadata: {
        status,
        queue_status: queueStatus,
      },
    });

    if (status === "CHECKED_IN" || queueStatus === "WAITING_FOR_VITALS") {
      await queueClinicalWorkflowNotification(context, {
        templateKey: "appointment_checked_in",
        patientId: Number(rows[0].patient_id),
        appointmentId: id,
        sourceModule: "appointments",
        sourceRecordId: id,
        variables: {
          doctor_name: rows[0].doctor_id ? `Doctor #${rows[0].doctor_id}` : "Doctor",
          department: rows[0].department_id ? `Department #${rows[0].department_id}` : "Department",
          token_number: rows[0].token_number || "-",
        },
      });
    }
  }

  return NextResponse.json(
    rows[0]
  );
}
